              <CollapsibleSection title="Gestion de l'Inventaire" isOpen={sectionStates['inventory']} onToggle={() => toggleSection('inventory')}>
                <div className="bg-black/30 p-3 rounded-lg">
                  <p className="text-[11px] text-gray-400">Cliquez sur un article pour changer son statut (Vert: OK, Orange: Faible, Rouge: Critique).</p>
                </div>
              </CollapsibleSection>

              <CollapsibleSection title="Historique d'Activité" isOpen={sectionStates['logs']} onToggle={() => toggleSection('logs')}>
                <div className="bg-black/30 p-3 rounded-lg">
                  <p className="text-[11px] text-gray-400">Toutes les actions sont enregistrées avec date, heure, utilisateur et description.</p>
                </div>
